package com.example.oauthclient;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Controller;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.server.ResponseStatusException;
import org.springframework.web.util.UriComponentsBuilder;

import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URI;
import java.util.List;

@SpringBootApplication
public class OAuthClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }
}

@Controller
class OAuthController {

    private static final String AUTHORIZATION_ENDPOINT = "https://authorization-server.example.com/oauth/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/callback";
    private static final String RESPONSE_TYPE = "code";
    private static final List<String> SCOPES = List.of("read", "write");

    @GetMapping("/login")
    public void login(HttpServletResponse response) throws IOException {
        String authorizationUrl = UriComponentsBuilder
                .fromUriString(AUTHORIZATION_ENDPOINT)
                .queryParam("client_id", CLIENT_ID)
                .queryParam("redirect_uri", REDIRECT_URI)
                .queryParam("scope", String.join(" ", SCOPES))
                .queryParam("response_type", RESPONSE_TYPE)
                .build()
                .toUriString();

        response.sendRedirect(authorizationUrl);
    }

    @GetMapping("/callback")
    public void callback(@RequestParam MultiValueMap<String, String> params, HttpServletResponse response) throws IOException {
        if (params.containsKey("error")) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Authorization error: " + params.getFirst("error"));
        }

        String code = params.getFirst("code");
        if (code == null || code.isBlank()) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Missing authorization code");
        }

        response.setStatus(HttpServletResponse.SC_OK);
        response.setHeader(HttpHeaders.CONTENT_TYPE, "text/plain");
        response.getWriter().write("Authorization code received: " + code);
    }
}